const body = $input.first().json.body || $input.first().json;
const text = (body.text || body.message || '').trim();
const chatId = String(body.chatId || body.chat_id || '7713811206');

if (!text) {
  return [{ json: { error: true, specialist: 'none', label: '오류', systemPrompt: '', userMessage: '', chatId } }];
}

const SPECIALISTS = [
  { id: 'executive', icon: '\u{1F9ED}', label: '총괄', keywords: ['우선순위','뭐부터','정리해줘','로드맵','회의','핸드오프'], prompt: '너는 PRESSCO21의 총괄 비서다. 대표의 우선순위를 정리하고 프로젝트 간 조율을 담당한다. 상황→우선순위→다음 행동 포맷으로 간결하게 답해라.' },
  { id: 'strategy', icon: '\u{1F3DB}', label: '파트너클래스', keywords: ['파트너클래스','협회','강사','클래스','수강생','PRD','브랜드'], prompt: '너는 PRESSCO21 파트너클래스 전략가다. 꽃 공예 교육 플랫폼 전략, 강사 운영, 클래스 기획을 담당한다.' },
  { id: 'storefront', icon: '\u{1F6CD}', label: '스토어', keywords: ['메이크샵','상세페이지','장바구니','결제','카테고리','전환율'], prompt: '너는 PRESSCO21 메이크샵 스토어프론트 전문가다. UI/UX, 전환율 최적화, 상세페이지 개선을 담당한다.' },
  { id: 'crm', icon: '\u{1F4D2}', label: 'CRM', keywords: ['CRM','명세표','거래명세서','견적서','수금','입금','고객'], prompt: '너는 PRESSCO21 CRM 운영자다. 고객 관리, 정산, 거래명세서, 입금 처리를 담당한다.' },
  { id: 'automation', icon: '\u2699\uFE0F', label: '자동화', keywords: ['n8n','워크플로우','자동화','텔레그램','봇','API'], prompt: '너는 PRESSCO21 자동화 전문가다. n8n 워크플로우, 텔레그램 봇, API 연동을 담당한다.' },
  { id: 'knowledge', icon: '\u{1F4DA}', label: '지식', keywords: ['회사','재무','브랜드','정책','규정','매출','마진'], prompt: '너는 PRESSCO21 회사 지식 전문가다. 회사 전략, 재무, 브랜드 정책을 담당한다.' }
];

const lower = text.toLowerCase();
let matched = SPECIALISTS[0];
let maxScore = 0;
for (const s of SPECIALISTS) {
  let score = 0;
  for (const kw of s.keywords) { if (lower.includes(kw.toLowerCase())) score++; }
  if (score > maxScore) { maxScore = score; matched = s; }
}

return [{ json: { error: false, specialist: matched.id, icon: matched.icon, label: matched.label, systemPrompt: matched.prompt, userMessage: text, chatId } }];

